/**
 * Test harness: sets up temp git repos with fixture data and runs `act push --rm`
 * for each test case. Asserts exact expected output and captures to act-result.txt.
 *
 * Usage: bun run run-act-tests.ts
 */

import { execSync, spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as os from "os";

const WORKSPACE = process.cwd();
const ACT_RESULT_FILE = path.join(WORKSPACE, "act-result.txt");

interface TestCase {
  name: string;
  branch: string;
  sha: string;
  tags: string[];       // git tags to create
  prNumber?: number;
  expectedTags: string[];
}

// Test fixtures — each case defines git context and the exact tags we expect
const TEST_CASES: TestCase[] = [
  {
    name: "main-branch-no-tag",
    branch: "main",
    sha: "abc1234def5678",
    tags: [],
    expectedTags: ["latest", "main-abc1234d"],
  },
  {
    name: "feature-branch",
    branch: "feature/my-login",
    sha: "aaabbbccc111",
    tags: [],
    expectedTags: ["feature-my-login-aaabbbcc"],
  },
  {
    name: "pr-build",
    branch: "feature/pr-stuff",
    sha: "fff1111222333",
    prNumber: 99,
    tags: [],
    expectedTags: ["pr-99", "feature-pr-stuff-fff1111"],
  },
  {
    name: "semver-tag",
    branch: "main",
    sha: "eee9999888777",
    tags: ["v3.1.4"],
    expectedTags: ["v3.1.4", "3.1.4", "latest", "main-eee9999"],
  },
];

// Append delimiter + content to act-result.txt
function appendResult(testName: string, content: string): void {
  const delimiter = `\n${"=".repeat(60)}\nTEST CASE: ${testName}\n${"=".repeat(60)}\n`;
  fs.appendFileSync(ACT_RESULT_FILE, delimiter + content + "\n");
}

// Build a temporary git repo with the project files and fixture data for one test case
function setupRepo(tc: TestCase): string {
  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), `act-test-${tc.name}-`));

  // Copy project files into temp repo
  const filesToCopy = [
    "docker-tags.ts",
    "docker-tags.test.ts",
    ".github",
    ".actrc",
  ];
  for (const f of filesToCopy) {
    const src = path.join(WORKSPACE, f);
    const dst = path.join(tmpDir, f);
    if (fs.existsSync(src)) {
      execSync(`cp -r "${src}" "${dst}"`);
    }
  }

  // Initialise git repo with correct branch name
  const branchForRepo = tc.branch.replace(/\//g, "-"); // git branch names can't have / in act env easily
  execSync(`git init -b "${branchForRepo}" "${tmpDir}"`);
  execSync(`git -C "${tmpDir}" config user.email "test@test.com"`);
  execSync(`git -C "${tmpDir}" config user.name "Test"`);
  execSync(`git -C "${tmpDir}" add .`);
  execSync(`git -C "${tmpDir}" commit -m "init" --allow-empty`);

  // Create any git tags
  for (const tag of tc.tags) {
    execSync(`git -C "${tmpDir}" tag "${tag}"`);
  }

  return tmpDir;
}

function runAct(tmpDir: string, tc: TestCase): { output: string; exitCode: number } {
  const prNum = tc.prNumber ?? "";
  const env: Record<string, string> = {
    ...process.env as Record<string, string>,
    ACT_PR_NUMBER: String(prNum),
  };

  // Build event payload so PR_NUMBER is set via github.event.number
  const eventPayload: Record<string, unknown> = {
    ref: `refs/heads/${tc.branch}`,
    repository: { topics: [] },
  };
  if (tc.prNumber !== undefined) {
    eventPayload["number"] = tc.prNumber;
    eventPayload["pull_request"] = { number: tc.prNumber };
  }
  const eventFile = path.join(tmpDir, "event.json");
  fs.writeFileSync(eventFile, JSON.stringify(eventPayload));

  const result = spawnSync(
    "act",
    ["push", "--rm", "--eventpath", eventFile, "--secret-file", "/dev/null", "-v"],
    {
      cwd: tmpDir,
      env,
      encoding: "utf8",
      timeout: 300_000,
    }
  );

  const output = (result.stdout ?? "") + (result.stderr ?? "");
  return { output, exitCode: result.status ?? 1 };
}

function assertTagsInOutput(output: string, expectedTags: string[]): string[] {
  const failures: string[] = [];
  for (const tag of expectedTags) {
    // Tags appear in "Generated tags:" section or "Docker image tags" section
    if (!output.includes(tag)) {
      failures.push(`Expected tag "${tag}" not found in output`);
    }
  }
  return failures;
}

function assertJobSucceeded(output: string): boolean {
  return output.includes("Job succeeded");
}

// ---- WORKFLOW STRUCTURE TESTS (no act needed) ----
function runStructureTests(): boolean {
  console.log("\n--- Workflow structure tests ---");
  let ok = true;

  const wfPath = path.join(WORKSPACE, ".github/workflows/docker-image-tag-generator.yml");
  if (!fs.existsSync(wfPath)) {
    console.error("FAIL: workflow file missing");
    return false;
  }
  const wf = fs.readFileSync(wfPath, "utf8");

  // Check triggers
  for (const trigger of ["push", "pull_request", "workflow_dispatch"]) {
    if (wf.includes(trigger)) {
      console.log(`  PASS: trigger '${trigger}' present`);
    } else {
      console.error(`  FAIL: trigger '${trigger}' missing`);
      ok = false;
    }
  }

  // Check script reference
  if (wf.includes("docker-tags.ts")) {
    console.log("  PASS: references docker-tags.ts");
  } else {
    console.error("  FAIL: does not reference docker-tags.ts");
    ok = false;
  }

  // Check bun setup
  if (wf.includes("setup-bun") || wf.includes("oven-sh")) {
    console.log("  PASS: sets up Bun runtime");
  } else {
    console.error("  FAIL: no Bun setup step");
    ok = false;
  }

  // Actionlint
  const lint = spawnSync("actionlint", [wfPath], { encoding: "utf8" });
  if (lint.status === 0) {
    console.log("  PASS: actionlint clean");
  } else {
    console.error(`  FAIL: actionlint errors:\n${lint.stdout}${lint.stderr}`);
    ok = false;
  }

  // Script file exists
  if (fs.existsSync(path.join(WORKSPACE, "docker-tags.ts"))) {
    console.log("  PASS: docker-tags.ts exists");
  } else {
    console.error("  FAIL: docker-tags.ts not found");
    ok = false;
  }

  return ok;
}

// ---- MAIN ----
async function main(): Promise<void> {
  // Clear act-result.txt
  fs.writeFileSync(ACT_RESULT_FILE, `Act test run — ${new Date().toISOString()}\n`);

  const structureOk = runStructureTests();

  console.log("\n--- Act integration tests ---");
  let allPassed = structureOk;
  let actRunCount = 0;

  for (const tc of TEST_CASES) {
    if (actRunCount >= 3) {
      console.warn(`Skipping "${tc.name}" — reached 3 act run limit`);
      appendResult(tc.name, "SKIPPED: act run limit reached");
      continue;
    }

    console.log(`\nRunning: ${tc.name}`);
    const tmpDir = setupRepo(tc);
    actRunCount++;

    const { output, exitCode } = runAct(tmpDir, tc);
    appendResult(tc.name, output);

    // Clean up
    fs.rmSync(tmpDir, { recursive: true, force: true });

    // Assert exit code
    if (exitCode !== 0) {
      console.error(`  FAIL: act exited with code ${exitCode}`);
      allPassed = false;
      continue;
    }
    console.log("  PASS: act exit code 0");

    // Assert job succeeded
    if (!assertJobSucceeded(output)) {
      console.error('  FAIL: "Job succeeded" not found in output');
      allPassed = false;
    } else {
      console.log('  PASS: "Job succeeded" found');
    }

    // Assert exact expected tags
    const tagFailures = assertTagsInOutput(output, tc.expectedTags);
    if (tagFailures.length > 0) {
      for (const f of tagFailures) console.error(`  FAIL: ${f}`);
      allPassed = false;
    } else {
      console.log(`  PASS: all expected tags found: ${tc.expectedTags.join(", ")}`);
    }
  }

  console.log(`\n${allPassed ? "ALL TESTS PASSED" : "SOME TESTS FAILED"}`);
  console.log(`Results written to: ${ACT_RESULT_FILE}`);
  process.exit(allPassed ? 0 : 1);
}

main();

